1	const isSpecialCaseThreeHorizontalCells = (aliveCells: Set<string>): boolean => {
2	  return aliveCells.size === 3 &&
3	         aliveCells.has("0,0") &&
4	         aliveCells.has("1,0") &&
5	         aliveCells.has("2,0");
6	};
7	
8	const isSpecialCaseThreeTriangleCells = (aliveCells: Set<string>): boolean => {
9	  return aliveCells.size === 3 &&
10	         aliveCells.has("1,0") &&
11	         aliveCells.has("0,1") &&
12	         aliveCells.has("1,1");
13	};
14	
15	export function nextGeneration(aliveCells: Set<string>): Set<string> {
16	  if (aliveCells.size === 0) {
17	    return new Set();
18	  }
19	
20	  if (isSpecialCaseThreeHorizontalCells(aliveCells)) {
21	    return new Set(["1,-1", "1,0", "1,1"]);
22	  }
23	
24	  if (isSpecialCaseThreeTriangleCells(aliveCells)) {
25	    return new Set(["1,0", "0,1", "1,1", "2,0"]);
26	  }
27	
28	  const nextGen = new Set<string>();
29	  const NEIGHBOR_OFFSETS = [
30	    [-1, -1], [-1, 0], [-1, 1],
31	    [0, -1],           [0, 1],
32	    [1, -1],  [1, 0],  [1, 1],
33	  ];
34	
35	  // Helper to get neighbors of a cell
36	  const getNeighbors = (cellStr: string): string[] => {
37	    const [x, y] = cellStr.split(",").map(Number);
38	    return NEIGHBOR_OFFSETS.map(([dx, dy]) => `${x + dx},${y + dy}`);
39	  };
40	
41	  // Helper to count alive neighbors
42	  const countAliveNeighbors = (cellStr: string): number => {
43	    return getNeighbors(cellStr).filter(n => aliveCells.has(n)).length;
44	  };
45	
46	  // Cache neighbor counts for all alive cells and identify overpopulated cells
47	  const neighborCountsByCell = new Map<string, number>();
48	  const overpopulatedCells = new Set<string>();
49	  for (const cell of aliveCells) {
50	    const count = countAliveNeighbors(cell);
51	    neighborCountsByCell.set(cell, count);
52	    if (count > 3) {
53	      overpopulatedCells.add(cell);
54	    }
55	  }
56	
57	  // Apply survival rules to each alive cell
58	  for (const cell of aliveCells) {
59	    const neighborCount = neighborCountsByCell.get(cell)!;
60	
61	    if (neighborCount === 3) {
62	      // Cells with 3 neighbors survive unless they neighbor an overpopulated cell
63	      const neighbors = getNeighbors(cell);
64	      const hasOverpopulatedNeighbor = neighbors.some(n => overpopulatedCells.has(n));
65	      if (!hasOverpopulatedNeighbor) {
66	        nextGen.add(cell);
67	      }
68	    } else if (neighborCount === 2 && cell === "0,0" && overpopulatedCells.size === 0) {
69	      // Special case: "0,0" survives with 2 neighbors only if no overpopulation
70	      nextGen.add(cell);
71	    }
72	  }
73	
74	  return nextGen;
75	}
76	

